const body = $input.first().json.body;
const headers = $input.first().json.headers;

// Auth check
if (headers['x-webhook-secret'] !== 'REDACTED_WEBHOOK_SECRET') {
  return [{ json: { error: 'Unauthorized', statusCode: 401 } }];
}

const name = (body.name || '').trim();
if (!name) {
  return [{ json: { error: 'Name ist erforderlich', statusCode: 400 } }];
}

return [{ json: {
  name: name.substring(0, 200),
  description: (body.description || '').substring(0, 1000) || null,
  status: 'draft',
  start_date: body.start_date || null,
  end_date: body.end_date || null,
  calling_window_start: body.calling_window_start || '09:00',
  calling_window_end: body.calling_window_end || '18:00',
  calling_timezone: body.calling_timezone || 'Europe/Berlin',
  calling_days: body.calling_days || [1,2,3,4,5],
  cadence_config: body.cadence_config || { max_attempts: 5, intervals_minutes: [60,240,1440,4320,10080], voicemail_action: 'skip', leave_voicemail_after_attempt: 3 },
  target_filter: body.target_filter || null,
  system_prompt_override: body.system_prompt_override || null,
  first_message_override: body.first_message_override || null,
  statusCode: 0
} }];

const body = $input.first().json.body;
const headers = $input.first().json.headers;

if (headers['x-webhook-secret'] !== 'REDACTED_WEBHOOK_SECRET') {
  return [{ json: { error: 'Unauthorized', statusCode: 401 } }];
}

const id = (body.id || '').trim();
if (!id) {
  return [{ json: { error: 'Campaign ID ist erforderlich', statusCode: 400 } }];
}

// Build update object with only provided fields
const update = {};
if (body.name !== undefined) update.name = String(body.name).substring(0, 200);
if (body.description !== undefined) update.description = String(body.description).substring(0, 1000);
if (body.start_date !== undefined) update.start_date = body.start_date;
if (body.end_date !== undefined) update.end_date = body.end_date;
if (body.calling_window_start !== undefined) update.calling_window_start = body.calling_window_start;
if (body.calling_window_end !== undefined) update.calling_window_end = body.calling_window_end;
if (body.calling_timezone !== undefined) update.calling_timezone = body.calling_timezone;
if (body.calling_days !== undefined) update.calling_days = body.calling_days;
if (body.cadence_config !== undefined) update.cadence_config = body.cadence_config;
if (body.target_filter !== undefined) update.target_filter = body.target_filter;
if (body.system_prompt_override !== undefined) update.system_prompt_override = body.system_prompt_override;
if (body.first_message_override !== undefined) update.first_message_override = body.first_message_override;

return [{ json: { id, update: JSON.stringify(update), statusCode: 0 } }];

