const body = $input.first().json.body;
const headers = $input.first().json.headers;

if (headers['x-webhook-secret'] !== 'REDACTED_WEBHOOK_SECRET') {
  return [{ json: { error: 'Unauthorized', statusCode: 401 } }];
}

const campaignId = (body.campaign_id || '').trim();
const leadIds = body.lead_ids;

if (!campaignId) {
  return [{ json: { error: 'campaign_id ist erforderlich', statusCode: 400 } }];
}

if (!Array.isArray(leadIds) || leadIds.length === 0) {
  return [{ json: { error: 'lead_ids Array ist erforderlich', statusCode: 400 } }];
}

if (leadIds.length > 500) {
  return [{ json: { error: 'Maximal 500 Leads pro Request', statusCode: 400 } }];
}

return [{ json: { campaignId, leadIds, statusCode: 0 } }];

// Build batch update: set campaign_id for all leads
const data = $input.first().json;
const leadIds = data.leadIds;
const campaignId = data.campaignId;

// Emit individual items for each lead
return leadIds.map(id => ({ json: { leadId: id, campaignId } }));

// Count successful assignments
const items = $input.all();
const successCount = items.filter(i => !i.json.error && !i.json.statusCode).length;
const totalLeads = $('Split Lead IDs').all().length;
const campaignId = $('Add Leads Valid?').first().json.campaignId;

return [{ json: { 
  success: true, 
  assigned: successCount, 
  total: totalLeads, 
  campaign_id: campaignId 
} }];

